   218→// extractGitLabProject extracts the project namespace/name from a GitLab repository URL
   219→func extractGitLabProject(repoURL string) (string, error) {
   220→	parsedURL, err := url.Parse(repoURL)
   221→	if err != nil {
   222→		return "", fmt.Errorf("invalid repository URL: %w", err)
   223→	}
   224→
   225→	// Validate that this is an HTTPS URL
   226→	if parsedURL.Scheme != "https" {
   227→		return "", fmt.Errorf("repository URL must use HTTPS scheme, got: %s", parsedURL.Scheme)
   228→	}
   229→
   230→	// Validate that host is set (basic validation for proper URL)
   231→	if parsedURL.Host == "" {
   232→		return "", fmt.Errorf("repository URL must have a valid host")
   233→	}
   234→
   235→	// Remove leading slash and .git suffix
   236→	path := strings.TrimPrefix(parsedURL.Path, "/")
   237→	path = strings.TrimSuffix(path, ".git")
   238→
   239→	if path == "" {
   240→		return "", fmt.Errorf("unable to extract project path from URL: %s", repoURL)
   241→	}
   242→
   243→	// Basic validation - should have at least namespace/project
   244→	pathParts := strings.Split(path, "/")
   245→	if len(pathParts) < 2 {
   246→		return "", fmt.Errorf("GitLab project path should have at least namespace/project format, got: %s", path)
   247→	}
   248→
   249→	return path, nil
   250→}
